const txns = $('Read Transactions').all().map(t => t.json);
const budgets = $('Read Budgets').all().map(b => b.json);

const now = new Date();
const currentMonth = now.getMonth();
const currentYear = now.getFullYear();

// Filter current month transactions
const monthTxns = txns.filter(t => {
  if (!t.date) return false;
  const d = new Date(t.date);
  return d.getMonth() === currentMonth && d.getFullYear() === currentYear && t.type === 'debit';
});

// Calculate spend per category
const spendByCategory = {};
monthTxns.forEach(t => {
  const cat = (t.category || 'other').toLowerCase();
  spendByCategory[cat] = (spendByCategory[cat] || 0) + parseFloat(t.amount || 0);
});

// Compare vs budgets
const alerts = [];
const summary = [];
let totalSpend = 0;
let totalBudget = 0;

budgets.forEach(b => {
  const cat = b.category.toLowerCase();
  const limit = parseFloat(b.monthly_limit || 0);
  const spent = spendByCategory[cat] || 0;
  const pct = limit > 0 ? (spent / limit * 100) : 0;
  totalSpend += spent;
  totalBudget += limit;

  let icon = '\u2705'; // green check
  if (pct >= 100) icon = '\ud83d\udd34'; // red
  else if (pct >= 80) icon = '\u26a0\ufe0f'; // warning

  summary.push(`${icon} ${b.category}: \u20b9${spent.toLocaleString()} / \u20b9${limit.toLocaleString()} (${pct.toFixed(0)}%)`);

  if (pct >= 100) {
    alerts.push(`\ud83d\udd34 OVERSPENT: ${b.category} at ${pct.toFixed(0)}% (\u20b9${(spent - limit).toLocaleString()} over)`);
  } else if (pct >= 80) {
    alerts.push(`\u26a0\ufe0f WARNING: ${b.category} at ${pct.toFixed(0)}% (\u20b9${(limit - spent).toLocaleString()} remaining)`);
  }
});

const daysInMonth = new Date(currentYear, currentMonth + 1, 0).getDate();
const dayOfMonth = now.getDate();
const projectedSpend = totalSpend / dayOfMonth * daysInMonth;

let msg = `\ud83d\udcb0 *Daily Budget Report*\n`;
msg += `\ud83d\udcc5 ${now.toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })}\n\n`;

if (alerts.length > 0) {
  msg += `*\u26a0\ufe0f Alerts:*\n${alerts.join('\n')}\n\n`;
}

msg += `*Category Breakdown:*\n${summary.join('\n')}\n\n`;
msg += `*Total:* \u20b9${totalSpend.toLocaleString()} / \u20b9${totalBudget.toLocaleString()}\n`;
msg += `*Projected Month-End:* \u20b9${projectedSpend.toLocaleString('en-IN', {maximumFractionDigits: 0})}\n`;
msg += `*Day ${dayOfMonth} of ${daysInMonth}*`;

return [{ json: { message: msg, has_alerts: alerts.length > 0 } }];
